arguments.command:
# Check the openclaw config for feishu accounts
cat ~/.openclaw/openclaw.json 2>/dev/null | python3 -c "
import json, sys
config = json.load(sys.stdin)
# Look for feishu-related config
if 'channels' in config:
    print('=== channels ===')
    for ch_name, ch_cfg in config.get('channels', {}).items():
        if 'feishu' in ch_name.lower() or 'lark' in ch_name.lower():
            print(f'{ch_name}: {json.dumps({k:v for k,v in ch_cfg.items() if k not in (\"appSecret\",)}, indent=2)}')
if 'accounts' in config:
    print('=== accounts ===')
    for acct_name, acct_cfg in config.get('accounts', {}).items():
        print(f'{acct_name}: keys={list(acct_cfg.keys())}')
if 'feishu' in config:
    fp = config['feishu']
    safe = {k:v for k,v in fp.items() if 'secret' not in k.lower() and 'key' not in k.lower() and 'token' not in k.lower()}
    print(f'=== feishu (safe) ===')
    print(json.dumps(safe, indent=2))
" 2>&1 | head -50

