#!/usr/bin/env python3
"""
桥接脚本：将 aggressive 组合持仓（paper_aggressive_portfolio_positions_latest_cn.csv）
转换为 exit_engine 兼容的 holdings 格式，合并到 aggressive paper trading 管线。

用法：
  python3 aggressive_portfolio_to_exit_holdings.py \
    --portfolio paper_aggressive_portfolio_positions_latest_cn.csv \
    --existing paper_v4_3_aggressive_exit_holdings_20260429.csv \
    --output paper_v4_3_aggressive_exit_holdings_20260429.csv
"""

import argparse
import sys
from pathlib import Path

import pandas as pd


def load_portfolio_positions_cn(path: Path) -> pd.DataFrame:
    """加载中文列名的组合持仓 CSV，转为 exit_engine holdings 格式"""
    if not path.exists():
        print(f"[WARN] 组合持仓文件不存在: {path}")
        return pd.DataFrame(columns=["symbol", "quantity", "cost_price"])

    df = pd.read_csv(path)
    if df.empty:
        return pd.DataFrame(columns=["symbol", "quantity", "cost_price"])

    # 中文列名映射
    COL_MAP = {
        "股票代码": "symbol",
        "持仓数量": "quantity",
        "成本价": "cost_price",
    }

    # 尝试中文列名，否则用索引
    mapped = {}
    for cn, en in COL_MAP.items():
        if cn in df.columns:
            mapped[en] = df[cn]
        else:
            print(f"[WARN] 列 '{cn}' 不存在，可用列: {list(df.columns)}")
            return pd.DataFrame(columns=["symbol", "quantity", "cost_price"])

    out = pd.DataFrame(mapped)
    out["quantity"] = pd.to_numeric(out["quantity"], errors="coerce").fillna(0).astype(int)
    out["cost_price"] = pd.to_numeric(out["cost_price"], errors="coerce").fillna(0.0)
    out = out[out["quantity"] > 0].copy()
    return out[["symbol", "quantity", "cost_price"]]


def merge_holdings(existing_path: Path, new_holdings: pd.DataFrame) -> pd.DataFrame:
    """合并现有持仓和新增持仓，按 symbol 去重（保留现有关键值）"""
    if existing_path.exists():
        existing = pd.read_csv(existing_path)
    else:
        existing = pd.DataFrame(columns=["symbol", "quantity", "cost_price"])

    if existing.empty and new_holdings.empty:
        return pd.DataFrame(columns=["symbol", "quantity", "cost_price"])

    combined = pd.concat([existing, new_holdings], ignore_index=True)
    # 保留第一次出现的 symbol（现有的优先）
    combined = combined.drop_duplicates(subset=["symbol"], keep="first")
    return combined.reset_index(drop=True)


def main():
    parser = argparse.ArgumentParser(
        description="Aggressive 组合持仓 → exit_engine holdings 格式"
    )
    parser.add_argument(
        "--portfolio",
        required=True,
        type=Path,
        help="aggressive 组合持仓 CSV (中文列名)",
    )
    parser.add_argument(
        "--existing",
        type=Path,
        help="现有的 paper_v4_3_aggressive_exit_holdings CSV",
    )
    parser.add_argument(
        "--output",
        required=True,
        type=Path,
        help="合并后的 holdings 输出路径",
    )
    args = parser.parse_args()

    # 1. 加载 aggressive 组合持仓
    portfolio = load_portfolio_positions_cn(args.portfolio)
    print(f"[INFO] 组合持仓: {len(portfolio)} 只")
    if not portfolio.empty:
        for _, row in portfolio.iterrows():
            print(f"  {row['symbol']} qty={row['quantity']} cost={row['cost_price']:.4f}")

    # 2. 与现有持仓合并
    merged = merge_holdings(args.existing, portfolio)
    print(f"[INFO] 合并后总持仓: {len(merged)} 只")

    # 3. 写输出
    merged.to_csv(args.output, index=False)
    print(f"[OK] 已写入: {args.output}")

    return 0


if __name__ == "__main__":
    sys.exit(main())

