def get_breadth_signals_quick():
    """Sina 5 秒快速回退 — 盘后/非交易日 baostock 超时时用"""
    codes = {
        "sh.000300": "s_sh000300",
        "sz.399006": "s_sz399006",
        "sh.000905": "s_sh000905",
    }
    signals = {}
    for key, sina_code in codes.items():
        url = f"http://hq.sinajs.cn/list={sina_code}"
        req = urllib.request.Request(url, headers={"Referer": "http://finance.sina.com.cn"})
        try:
            with urllib.request.urlopen(req, timeout=5, context=_ctx) as r:
                data = r.read().decode("gbk", errors="replace")
            # Sina format: name, open, yesterday_close, current, high, low, volume, amount, ...
            payload = data.split('"')
            if len(payload) < 2:
                continue
            parts = payload[1].split(",")
            if len(parts) < 4:
                continue
            name = parts[0]
            yesterday_close = float(parts[2]) if parts[2] else 0
            current = float(parts[3]) if parts[3] else 0
            if yesterday_close:
                pct_chg = round((current - yesterday_close) / yesterday_close * 100, 3)
            else:
                pct_chg = 0
            signals[key] = {
                "close": round(current, 4),
                "pct_chg": pct_chg,
                "above_ma20": None,
                "mom_5d": None,
                "mom_20d": None,
            }
        except Exception as e:
            sys.stderr.write(f"Sina fallback failed for {key}: {e}\n")
    # 创业板/沪深300 比率
    if "sz.399006" in signals and "sh.000300" in signals:
        cyb = signals["sz.399006"]["close"]
        hs3 = signals["sh.000300"]["close"]
        if hs3:
            signals["创业板/沪深300比率"] = round(cyb / hs3, 5)
    return signals


