def _patch_ma20_from_baostock(signals: dict):
    """用 baostock 补齐 MA20/动量字段，失败静默"""
    import signal as _signal
    import baostock as bs
    import pandas as pd

    def _handler(signum, frame):
        raise TimeoutError()

    old_handler = _signal.signal(_signal.SIGALRM, _handler)
    _signal.alarm(10)  # baostock 只给 10s，超时就放弃

    try:
        bs.login()
    except Exception:
        _signal.alarm(0)
        _signal.signal(_signal.SIGALRM, old_handler)
        return

    try:
        indices = {"sh.000300": "沪深300", "sz.399006": "创业板指", "sh.000905": "中证500"}
        today_fmt = datetime.now().strftime("%Y-%m-%d")
        for code, name in indices.items():
            try:
                rs = bs.query_history_k_data_plus(
                    code, "date,close,pctChg",
                    start_date="2024-01-01", end_date=today_fmt,
                    frequency="d", adjustflag="2"
                )
            except Exception:
                continue
            if rs is None or rs.error_code != "0":
                continue
            rows = []
            while rs.next() and rs.error_code == "0":
                rows.append(rs.get_row_data())
            if len(rows) < 25:
                continue
            df = pd.DataFrame(rows, columns=["date", "close", "pctChg"])
            df["close"] = pd.to_numeric(df["close"], errors="coerce")
            df["pctChg"] = pd.to_numeric(df["pctChg"], errors="coerce")
            df = df.dropna(subset=["close"])
            if len(df) < 25:
                continue
            ma20 = df["close"].rolling(20).mean()
            above_ma20 = bool(df["close"].iloc[-1] > ma20.iloc[-1]) if not ma20.isna().all() else None
            if name in signals:
                signals[name]["above_ma20"] = above_ma20
                signals[name]["mom_5d"] = round(float(df["pctChg"].tail(5).mean()), 3)
                signals[name]["mom_20d"] = round(float(df["pctChg"].tail(20).mean()), 3)
    finally:
        try:
            bs.logout()
        except Exception:
            pass
        _signal.alarm(0)
        _signal.signal(_signal.SIGALRM, old_handler)

